import{_ as t,o as r,c as e,a2 as o}from"./chunks/framework.DnrXFDHb.js";const p=JSON.parse('{"title":"黃豆追蹤日誌 — 2026-06-17（TST 05:00）","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-17.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-17.md"}'),i={name:"Deep32Q知識庫/產業洞察/黃豆研究/追蹤日誌/黃豆追蹤_2026-06-17.md"};function l(d,a,h,n,s,c){return r(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="黃豆追蹤日誌-—-2026-06-17-tst-05-00" tabindex="-1">黃豆追蹤日誌 — 2026-06-17（TST 05:00） <a class="header-anchor" href="#黃豆追蹤日誌-—-2026-06-17-tst-05-00" aria-label="Permalink to &quot;黃豆追蹤日誌 — 2026-06-17（TST 05:00）&quot;">​</a></h1><h2 id="本日敘事錨點" tabindex="-1">本日敘事錨點 <a class="header-anchor" href="#本日敘事錨點" aria-label="Permalink to &quot;本日敘事錨點&quot;">​</a></h2><p><strong>核心事件：MOU 已簽署，油價暴跌至戰前水準，黃豆成本端支撐全面消退。</strong></p><p>今天黃豆的核心驅動已從「戰爭溢價」轉向「基本面壓力」。油價從 120 美元跌至 76 美元，運輸、肥料、能源溢價同步崩塌，黃豆失去成本端支撐。但黃豆本身面臨更多壓力：</p><ol><li><strong>USDA 上調阿根廷產量至 5,000 萬噸</strong>：南美供給預期進一步寬鬆</li><li><strong>中國需求疲弱</strong>：美國農產品出口持續低迷</li><li><strong>美國壓榨量連續三個月下滑</strong>：5 月因季節性維修部分工廠停工</li><li><strong>美國天氣良好</strong>：播種進度順利，無重大天災</li></ol><p>簡單說，今天的黃豆不是「荷莫茲利空」，而是「多重利空同時發酵」。</p><p>查詢時間：2026-06-17 05:00 TST（UTC+8）。</p><hr><h2 id="_8-項追蹤指標檢查" tabindex="-1">8 項追蹤指標檢查 <a class="header-anchor" href="#_8-項追蹤指標檢查" aria-label="Permalink to &quot;8 項追蹤指標檢查&quot;">​</a></h2><h3 id="_1-usda-種植進度報告" tabindex="-1">1. USDA 種植進度報告 <a class="header-anchor" href="#_1-usda-種植進度報告" aria-label="Permalink to &quot;1. USDA 種植進度報告&quot;">​</a></h3><p>本週尚未公布最新進度。美國中西部天氣良好，播種順利，無重大延遲。短期內不會成為利多。<br> 來源：TradingEconomics (2026-06-16)、Agriculture of America (2026-06-11)</p><h3 id="_2-巴西供應-收割-出口-豐收" tabindex="-1">2. 巴西供應（收割 + 出口 + 豐收） <a class="header-anchor" href="#_2-巴西供應-收割-出口-豐收" aria-label="Permalink to &quot;2. 巴西供應（收割 + 出口 + 豐收）&quot;">​</a></h3><p>巴西大豆維持高產，6 月出口仍強但季節性放緩。南美供給壓力仍在，但邊際增量正在下降。<br> 來源：Commodity Board (2026-06-15)、Agrolatam (2026-06-12)</p><h3 id="_3-尿素價格-多單訊號" tabindex="-1">3. 尿素價格 + 多單訊號 <a class="header-anchor" href="#_3-尿素價格-多單訊號" aria-label="Permalink to &quot;3. 尿素價格 + 多單訊號&quot;">​</a></h3><p>荷莫茲重開預期升溫後，肥料與能源溢價的想像空間被壓縮。尿素今日無單獨重大新聞，維持「能源溢價退燒」判斷。<br> 來源：TradingEconomics (2026-06-16)</p><h3 id="_4-荷莫茲海峽通航狀態" tabindex="-1">4. 荷莫茲海峽通航狀態 <a class="header-anchor" href="#_4-荷莫茲海峽通航狀態" aria-label="Permalink to &quot;4. 荷莫茲海峽通航狀態&quot;">​</a></h3><p>MOU 已提前簽署，CENTCOM 封鎖解除。Trump 宣布海峽將 toll-free 開放。但航運業仍觀望——水雷風險、保險成本、伊朗潛在威脅需數週才能重建信心。<br> 來源：Maritime Executive (2026-06-15)、Reuters (2026-06-14)</p><h3 id="_5-中美貿易-中國進口" tabindex="-1">5. 中美貿易 + 中國進口 <a class="header-anchor" href="#_5-中美貿易-中國進口" aria-label="Permalink to &quot;5. 中美貿易 + 中國進口&quot;">​</a></h3><p>中國對美國農產品需求持續疲弱。儘管荷莫茲復航可能降低全球運輸成本，但對美豆的結構性提升尚未出現。<br> 來源：TradingEconomics (2026-06-16)、Agrolatam (2026-06-12)</p><h3 id="_6-天然氣價格" tabindex="-1">6. 天然氣價格 <a class="header-anchor" href="#_6-天然氣價格" aria-label="Permalink to &quot;6. 天然氣價格&quot;">​</a></h3><p>本日未針對天然氣的單獨重大更新。邏輯上與尿素相同：能源風險下降，肥料與壓榨成本的上行風險降低。<br> 查詢時間：2026-06-17 05:00 TST。</p><h3 id="_7-聖嬰-拉尼娜氣候風險" tabindex="-1">7. 聖嬰/拉尼娜氣候風險 <a class="header-anchor" href="#_7-聖嬰-拉尼娜氣候風險" aria-label="Permalink to &quot;7. 聖嬰/拉尼娜氣候風險&quot;">​</a></h3><p>目前報導偏中性，未出現「美國中西部重大天災轉向」的明確信號。天氣暫時不是黃豆的主驅動因子。<br> 來源：Commodity Board (2026-06-15)</p><h3 id="_8-cbot-價格區間" tabindex="-1">8. CBOT 價格區間 <a class="header-anchor" href="#_8-cbot-價格區間" aria-label="Permalink to &quot;8. CBOT 價格區間&quot;">​</a></h3><p>近月 CBOT 大豆約在 <strong>1,129.50 美分/蒲式耳（$11.295/蒲式耳）</strong>，較昨日上漲 0.92%，但仍處於四個月低點附近。<br> 來源：TradingEconomics (2026-06-16)</p><h3 id="交叉驗證說明" tabindex="-1">交叉驗證說明 <a class="header-anchor" href="#交叉驗證說明" aria-label="Permalink to &quot;交叉驗證說明&quot;">​</a></h3><p>本日取得的 CBOT 報價：</p><ul><li>類型 A（TradingEconomics）：1,129.50 美分（$11.295）</li><li>類型 B（Yahoo Finance）：1,113.50–1,121.00 美分</li></ul><p>比對後取 <strong>1,129.50 美分</strong> 為今日可信值。<br> 原因：TradingEconomics 提供最新更新（6/16），Yahoo 部分數據為延遲報價。兩者價差在合理範圍內（&lt;1.5%），取較新值。<br> 驗證時間：2026-06-17 05:00 TST。</p><hr><h2 id="有什麼變化" tabindex="-1">有什麼變化？ <a class="header-anchor" href="#有什麼變化" aria-label="Permalink to &quot;有什麼變化？&quot;">​</a></h2><h3 id="變化一-油價暴跌至戰前水準-成本端支撐全面消退" tabindex="-1">變化一：油價暴跌至戰前水準，成本端支撐全面消退 <a class="header-anchor" href="#變化一-油價暴跌至戰前水準-成本端支撐全面消退" aria-label="Permalink to &quot;變化一：油價暴跌至戰前水準，成本端支撐全面消退&quot;">​</a></h3><p>變化內容：WTI 跌至 76.68 美元，Brent 跌破 80 美元。<br> 為什麼：MOU 簽署、CENTCOM 封鎖解除、Trump 宣布 toll-free 通行。<br> 影響：運輸溢價、肥料溢價、風險溢價同步崩塌，對黃豆成本端形成壓力。<br> 關鍵節點：荷莫茲實際復航速度。<br> 來源：TradingEconomics (2026-06-16)、Yahoo Finance (2026-06-16)</p><h3 id="變化二-usda-上調阿根廷產量至-5-000-萬噸" tabindex="-1">變化二：USDA 上調阿根廷產量至 5,000 萬噸 <a class="header-anchor" href="#變化二-usda-上調阿根廷產量至-5-000-萬噸" aria-label="Permalink to &quot;變化二：USDA 上調阿根廷產量至 5,000 萬噸&quot;">​</a></h3><p>變化內容：USDA 6 月 WASDE 上調阿根廷大豆產量預估。<br> 為什麼：南美天氣良好，豐收預期實現。<br> 影響：全球供給預期進一步寬鬆，限制黃豆反彈空間。<br> 關鍵節點：後續月度 WASDE 與美國單產調整。<br> 來源：TradingEconomics (2026-06-16)</p><h3 id="變化三-中國需求疲弱-美國壓榨量下滑" tabindex="-1">變化三：中國需求疲弱 + 美國壓榨量下滑 <a class="header-anchor" href="#變化三-中國需求疲弱-美國壓榨量下滑" aria-label="Permalink to &quot;變化三：中國需求疲弱 + 美國壓榨量下滑&quot;">​</a></h3><p>變化內容：中國對美農產品需求持續低迷，美國 5 月壓榨量連續第三個月下滑。<br> 為什麼：季節性維修 + 中國採購策略轉向。<br> 影響：需求端缺乏引擎，黃豆難以獲得上方動能。<br> 關鍵節點：中國採購政策、美國壓榨利潤。<br> 來源：TradingEconomics (2026-06-16)</p><hr><h2 id="情景分析-因荷莫茲-央行變數高度不確定" tabindex="-1">情景分析（因荷莫茲+央行變數高度不確定） <a class="header-anchor" href="#情景分析-因荷莫茲-央行變數高度不確定" aria-label="Permalink to &quot;情景分析（因荷莫茲+央行變數高度不確定）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>情境</th><th style="text-align:right;">發生機率</th><th>CBOT 價格影響</th><th>傳導機制</th></tr></thead><tbody><tr><td>荷莫茲順利復航、Fed 偏鴿</td><td style="text-align:right;">中低</td><td>偏向 11.00–11.20 美元</td><td>能源溢價消退 + 降息預期降溫，但成本支撐同步消失</td></tr><tr><td>復航延後、Fed 偏鷹</td><td style="text-align:right;">中高</td><td>偏向 11.20–11.60 美元</td><td>部分溢價回溫 + 美元走強壓制出口</td></tr><tr><td>復航順利但中國加碼採購</td><td style="text-align:right;">低</td><td>偏向 11.40–11.80 美元</td><td>需求面突破，改變供需格局</td></tr></tbody></table><hr><h2 id="延續昨日敘事" tabindex="-1">延續昨日敘事 <a class="header-anchor" href="#延續昨日敘事" aria-label="Permalink to &quot;延續昨日敘事&quot;">​</a></h2><p>昨日報告指出：市場從「戰爭交易」轉向「停火交易」，黃豆回到「能源溢價消退 + WASDE 中性 + 巴西供給仍強」的三方拉鋸。</p><p>今天確認：MOU 已提前簽署、油價暴跌至戰前水準、成本端支撐全面消退。黃豆的壓力已從「荷莫茲是否復航」轉向「基本面是否能撐住」。</p><p>短期重點：Fed Warsh 記者會的政策語氣 + 中國採購動態。</p><p>查詢時間：2026-06-17 05:00 TST。</p>',46)])])}const u=t(i,[["render",l]]);export{p as __pageData,u as default};
